package main

import (
    "fmt"
    "sync"
    "time"
)

func basicConcurrency() {
    var wg sync.WaitGroup

    for i := 0; i < 5; i++ {
        wg.Add(1)
        go func(n int) {
            defer wg.Done()
            fmt.Printf("Worker %d starting\n", n)
            time.Sleep(time.Second)
            fmt.Printf("Worker %d done\n", n)
        }(i)
    }

    wg.Wait()
    fmt.Println("All workers completed")
}

func fetchWithResult() {
    results := make(chan string, 3)

    go func() { results <- fetch("url1") }()
    go func() { results <- fetch("url2") }()
    go func() { results <- fetch("url3") }()

    for i := 0; i < 3; i++ {
        fmt.Println(<-results)
    }
}

type Job struct {
    ID   int
    Data string
}

type Result struct {
    JobID int
    Value string
    Err   error
}

func WorkerPool(ctx context.Context, numWorkers int, jobs <-chan Job) <-chan Result {
    results := make(chan Result, numWorkers)
    var wg sync.WaitGroup

    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go func(workerID int) {
            defer wg.Done()
            for {
                select {
                case job, ok := <-jobs:
                    if !ok {
                        return
                    }
                    result := processJob(job)
                    select {
                    case results <- result:
                    case <-ctx.Done():
                        return
                    }
                case <-ctx.Done():
                    return
                }
            }
        }(i)
    }

    go func() {
        wg.Wait()
        close(results)
    }()

    return results
}

type RateLimiter struct {
    tokens chan struct{}
    ticker *time.Ticker
    quit   chan struct{}
}

func NewRateLimiter(rate int, burst int) *RateLimiter {
    rl := &RateLimiter{
        tokens: make(chan struct{}, burst),
        ticker: time.NewTicker(time.Second / time.Duration(rate)),
        quit:   make(chan struct{}),
    }

    for i := 0; i < burst; i++ {
        rl.tokens <- struct{}{}
    }

    go func() {
        for {
            select {
            case <-rl.ticker.C:
                select {
                case rl.tokens <- struct{}{}:
                default: // Bucket full
                }
            case <-rl.quit:
                return
            }
        }
    }()

    return rl
}

func (rl *RateLimiter) Wait(ctx context.Context) error {
    select {
    case <-rl.tokens:
        return nil
    case <-ctx.Done():
        return ctx.Err()
    }
}

type Semaphore chan struct{}

func New(n int) Semaphore {
    return make(chan struct{}, n)
}

func (s Semaphore) Acquire(ctx context.Context) error {
    select {
    case s <- struct{}{}:
        return nil
    case <-ctx.Done():
        return ctx.Err()
    }
}

func (s Semaphore) Release() {
    <-s
}

func processUsers(ctx context.Context, users []User) error {
    sem := New(10) // Max 10 concurrent
    var wg sync.WaitGroup

    for _, user := range users {
        wg.Add(1)
        go func(u User) {
            defer wg.Done()
            if err := sem.Acquire(ctx); err != nil {
                return
            }
            defer sem.Release()
            processUser(ctx, u)
        }(user)
    }

    wg.Wait()
    return nil
}

type Cache struct {
    mu    sync.RWMutex
    items map[string]interface{}
}

func (c *Cache) Get(key string) (interface{}, bool) {
    c.mu.RLock()
    defer c.mu.RUnlock()
    item, exists := c.items[key]
    return item, exists
}

func (c *Cache) Set(key string, value interface{}) {
    c.mu.Lock()
    defer c.mu.Unlock()
    c.items[key] = value
}

var (
    instance *Database
    once     sync.Once
)

func GetDatabase() *Database {
    once.Do(func() {
        instance = &Database{conn: "connection_string"}
    })
    return instance
}

import (
    "context"
    "testing"
    "go.uber.org/goleak"
)

func TestWorkerPoolCancellation(t *testing.T) {
    defer goleak.VerifyNone(t)

    ctx, cancel := context.WithCancel(context.Background())
    jobs := make(chan Job, 10)
    results := WorkerPool(ctx, 5, jobs)

    // Send some jobs
    jobs <- Job{ID: 1, Data: "test"}

    // Read one result
    <-results

    // Cancel context
    cancel()
    close(jobs)

    // Drain remaining results; pool must close
    for range results {
    }
}

func TestWorkerPoolBench(b *testing.B) {
    ctx := context.Background()
    jobs := make(chan Job, 1000)
    results := WorkerPool(ctx, 10, jobs)

    go func() {
        for i := 0; i < b.N; i++ {
            jobs <- Job{ID: i, Data: "bench"}
        }
        close(jobs)
    }()

    for range results {
    }
}
